  6→import { INetworkAccount } from '../../types/network-account.type';
  7→import { INetworkService, ISweepBaseParams } from '../../types/network-service';
  8→import { SupportedNetworks } from '../../types/network.type';
  9→import { Decimal } from 'decimal.js';
 10→import {
 11→  IGetTransactionHistoryParams,
 12→  INetworkTransaction,
 13→} from '@modules/networks/types/network.type';
 14→import { GoldrushService } from '@modules/goldrush/services/goldrush.service';
 15→import { networksConfigs } from '@configs/networks.configs';
 16→import { ConfigType } from '@nestjs/config';
 17→
 18→@Injectable()
 19→export class EthereumNetworkService implements INetworkService {
 20→  constructor(
 21→    @Inject(DATABASE_CONNECTION_TOKEN) private readonly db: Db,
 22→    private readonly currencyService: CurrencyService,
 23→    private readonly goldrushService: GoldrushService,
 24→    @Inject(networksConfigs.KEY)
 25→    private readonly networksConf: ConfigType<typeof networksConfigs>,
 26→  ) {
 27→    this.ethWeb = new ethers.JsonRpcProvider(
 28→      `https://sepolia.infura.io/v3/${this.networksConf.ethereum.sepoliaApiKey}`,
 29→    );
 30→  }
 31→  private ethWeb: ethers.JsonRpcProvider;
 32→  readonly networkName = SupportedNetworks.ETHEREUM;
 33→  /**
 34→   * Creates a new Ethereum account (wallet)
 35→   * Generates a random wallet with a new private key
 36→   * @returns IEthereumAccount with address, privateKey, and publicKey
 37→   */
 38→  async createAccount(): Promise<INetworkAccount> {
 39→    // Generate a random wallet
 40→    const wallet = ethers.Wallet.createRandom(this.ethWeb);
 41→    // Get the public key from the wallet's signing key
 42→    // In Ethereum, the public key is 66 bytes (0x + 64 hex characters)
 43→    const publicKey = wallet.signingKey.publicKey;
 44→
 45→    return {
 46→      address: wallet.address, // Ethereum address in checksummed format (0x...)
 47→      privateKey: wallet.privateKey, // Private key (0x + 64 hex characters)
 48→      publicKey: publicKey, // Public key (0x + 128 hex characters)
 49→      meta: JSON.parse(JSON.stringify(wallet)),
 50→    };
 51→  }
 52→
 53→  async getBalance(address: string): Promise<string> {
 54→    const balance = await this.ethWeb.getBalance(address);
 55→    return ethers.formatEther(balance);
 56→  }
 57→
 58→  /**
 59→   * Gets the balance of an ERC20 token for a given address
 60→   * @param address The Ethereum address to check
 61→   * @param contractAddress The ERC20 token contract address
 62→   * @param decimals The number of decimals for the token
 63→   * @returns The formatted token balance as a string
 64→   */
 65→  async getTokenBalance(
 66→    address: string,
 67→    contractAddress: string,
 68→    decimals: number,
 69→  ): Promise<string> {
 70→    // Standard ERC20 ABI - only need balanceOf function
 71→    const erc20Abi = [
 72→      'function balanceOf(address owner) view returns (uint256)',
 73→    ];
 74→
 75→    const contract = new ethers.Contract(
 76→      contractAddress,
 77→      erc20Abi,
 78→      this.ethWeb,
 79→    );
 80→
 81→    const balance = await contract.balanceOf(address);
 82→    return ethers.formatUnits(balance, decimals);
 83→  }
 84→
 85→  /**
 86→   * Sweeps ERC-20 tokens from a one-time wallet to a destination address
 87→   * @param oneTimeWalletPrivateKey Private key of the one-time wallet
 88→   * @param currencyCode Currency code (e.g., 'USDT')
 89→   * @param destinationAddress Address to sweep tokens to
 90→   * @returns Transaction hash
 91→   */
 92→  async sweepToken(
 93→    oneTimeWalletPrivateKey: string,
 94→    currencyCode: string,
 95→    destinationAddress: string,
 96→  ): Promise<{ transactionHash: string; amount: string }> {
 97→    try {
 98→      // Get currency to find contract address
 99→      const currency = await this.currencyService.getCurrencyByCodeAndNetwork(
100→        currencyCode,
101→        SupportedNetworks.ETHEREUM,
102→      );
103→
104→      if (!currency || !currency.contractAddress) {
105→        throw new Error(
106→          `Currency ${currencyCode} not found or missing contract address`,
107→        );
108→      }
109→
110→      const contractAddress = currency.contractAddress;
111→
112→      // Create wallet from private key
113→      const wallet = new ethers.Wallet(oneTimeWalletPrivateKey, this.ethWeb);
114→
115→      // Standard ERC-20 ABI - transfer function
116→      const erc20Abi = [
117→        'function transfer(address to, uint256 amount) returns (bool)',
118→        'function balanceOf(address owner) view returns (uint256)',
119→      ];
120→
121→      // Create contract instance
122→      const contract = new ethers.Contract(contractAddress, erc20Abi, wallet);
123→
124→      // Get balance
125→      const balance = await contract.balanceOf(wallet.address);
126→
127→      if (balance === 0n) {
128→        throw new Error('No tokens to sweep');
129→      }
130→
131→      // Transfer all tokens to destination
132→      const tx = await contract.transfer(destinationAddress, balance);
133→      const receipt = await tx.wait();
134→
135→      return { amount: balance.toString(), transactionHash: receipt.hash };
136→    } catch (error) {
137→      const errorMessage =
138→        error instanceof Error ? error.message : String(error);
139→      throw new Error(`Failed to sweep token: ${errorMessage}`);
140→    }
141→  }
142→
143→  /**
144→   * Sweeps ETH from a one-time wallet to a destination address
145→   * @param oneTimeWalletPrivateKey Private key of the one-time wallet
146→   * @param params Parameters for the sweep
147→   * @returns Transaction hash
148→   */
149→  async sweepBase(
150→    params: ISweepBaseParams,
151→  ): Promise<{ transactionHash: string; amount: string }> {
152→    try {
153→      // Create wallet from private key
154→      const wallet = new ethers.Wallet(params.fromPrivateKey, this.ethWeb);
155→
156→      // Get balance
157→      const balance = await this.ethWeb.getBalance(wallet.address);
158→
159→      if (balance === 0n) {
160→        throw new Error('No ETH to sweep');
161→      }
162→
163→      // Estimate gas cost for the transaction
164→      const gasPrice = await this.ethWeb.getFeeData();
165→      const estimatedGas = 21000n; // Standard ETH transfer gas limit
166→      const gasCost = (gasPrice.gasPrice || 0n) * estimatedGas;
167→
168→      // Calculate amount to send (subtract gas cost)
169→      const amountToSend = balance > gasCost ? balance - gasCost : 0n;
170→
171→      if (amountToSend === 0n) {
172→        throw new Error('Insufficient balance after gas deduction');
173→      }
174→
175→      const sendAmount = params.amount
176→        ? new Decimal(params.amount).mul('1000000000000000000')
177→        : new Decimal(amountToSend.toString());
178→
179→      // Transfer ETH to destination
180→      const tx = await wallet.sendTransaction({
181→        to: params.toAddress,
182→        value: BigInt(sendAmount.toString()),
183→        gasLimit: estimatedGas,
184→      });
185→
186→      const receipt = await tx.wait(2); // Wait for 2 confirmations
187→
188→      return { transactionHash: receipt.hash, amount: sendAmount.toString() };
189→    } catch (error) {
190→      const errorMessage =
191→        error instanceof Error ? error.message : String(error);
192→      throw new Error(`Failed to sweep ETH: ${errorMessage}`);
193→    }
194→  }
195→
196→  async getTransactionHistory(
197→    options: IGetTransactionHistoryParams,
198→  ): Promise<INetworkTransaction[]> {
199→    if (options.contractAddress) {
200→      return this.goldrushService.getERC20TransfersToAdressFromDate({
201→        toAddress: options.address,
202→        network: SupportedNetworks.ETHEREUM,
203→        fromDate: new Date(options.sinceTimestamp),
204→        contractAddress: options.contractAddress,
205→      });
206→    }
207→    return this.goldrushService.getNativeTransfersToAdressFromDate({
208→      toAddress: options.address,
209→      network: SupportedNetworks.ETHEREUM,
210→      fromDate: new Date(options.sinceTimestamp),
211→      contractAddress: options.contractAddress,
212→    });
213→  }
214→}
