  1→import { BalanceService } from '@modules/balance/services/balance.service';
  2→import {
  3→  Inject,
  4→  Injectable,
  5→  Logger,
  6→  BadRequestException,
  7→} from '@nestjs/common';
  8→import { DATABASE_CONNECTION_TOKEN } from '@shared/database/constant';
  9→import { Db } from '@shared/database/types';
 10→import {
 11→  IInitiateDeposit,
 12→  IInitiateDepositResult,
 13→} from '../types/initiate-deposit';
 14→import { DepositStatus } from '@entities/deposit.entity';
 15→import { UUID } from 'crypto';
 16→import { InjectQueue } from '@nestjs/bullmq';
 17→import { Queue } from 'bullmq';
 18→import { DEPOSIT_QUEUE_NAME } from '../constant';
 19→import { DepositJobsEnum } from '../jobs';
 20→import { NetworksService } from '@modules/networks/services/networks.service';
 21→import { DepositPoolService } from './deposit-pool.service';
 22→import { ControlledTransaction, Selectable } from 'kysely';
 23→import { Database } from '../../../db/database.type';
 24→import { DepositEntity } from '@entities/deposit.entity';
 25→import { CurrencyEntity } from '@entities/balance.entity';
 26→
 27→@Injectable()
 28→export class DepositService {
 29→  private readonly logger = new Logger(DepositService.name);
 30→
 31→  constructor(
 32→    @Inject(DATABASE_CONNECTION_TOKEN) private readonly db: Db,
 33→    private readonly balanceService: BalanceService,
 34→    private readonly networksService: NetworksService,
 35→    private readonly depositPoolService: DepositPoolService,
 36→    @InjectQueue(DEPOSIT_QUEUE_NAME) private readonly depositQueue: Queue,
 37→  ) {}
 38→
 39→  /**
 40→   * Initiates a deposit by creating a deposit record and getting a pool account
 41→   * Returns a payment link with the deposit address where the user should send tokens
 42→   * Also schedules a monitoring job to observe when the payment is received
 43→   *
 44→   * Pool-based deposit logic:
 45→   * - All deposits use global pool accounts
 46→   * - Pool accounts are locked to specific currencies when used for deposits
 47→   * - Funds are swept to outstanding accounts (configured via environment variables)
 48→   */
 49→  async initiateDeposit(
 50→    options: IInitiateDeposit,
 51→  ): Promise<IInitiateDepositResult> {
 52→    const trx = await this.db.startTransaction().execute();
 53→
 54→    try {
 55→      const { currency } = await this.validateDepositInitiation(options, trx);
 56→
 57→      if (options.amount < currency.minDepositAmount) {
 58→        throw new BadRequestException(
 59→          `Amount is less than minimum deposit amount`,
 60→        );
 61→      }
 62→
 63→      const poolAccount =
 64→        await this.depositPoolService.getAndLockAvailablePoolAccount(trx, {
 65→          network: options.currencyNetwork,
 66→          currencyId: currency.id,
 67→        });
 68→      const deposit = await this.createDepositRecord(
 69→        options,
 70→        poolAccount.id,
 71→        trx,
 72→      );
 73→      const paymentLinkUrl = await this.generateAndUpdatePaymentLink(
 74→        deposit.id,
 75→        trx,
 76→      );
 77→
 78→      await this.depositPoolService.setDepositIdOnLockRecord(
 79→        deposit.id,
 80→        poolAccount.id,
 81→        currency.id,
 82→        trx,
 83→      );
 84→
 85→      await this.scheduleMonitoringJob(deposit.id, options, currency.id);
 86→      await trx.commit().execute();
 87→
 88→      this.logger.log({
 89→        message: 'Deposit initiated',
 90→        depositId: deposit.id,
 91→        paymentLink: paymentLinkUrl,
 92→        isBaseCurrency: currency.contractAddress === null,
 93→      });
 94→
 95→      return { paymentLink: paymentLinkUrl, depositId: deposit.id };
 96→    } catch (error) {
 97→      await trx.rollback().execute();
 98→      this.logger.error({ error, message: 'Failed to initiate deposit' });
 99→      throw error;
100→    }
101→  }
102→
103→  /**
104→   * Validates deposit initiation requirements
105→   */
106→  private async validateDepositInitiation(
107→    options: IInitiateDeposit,
108→    trx: ControlledTransaction<Database, []>,
109→  ): Promise<{ currency: Selectable<CurrencyEntity> }> {
110→    const currency = await trx
111→      .selectFrom('currency')
112→      .selectAll()
113→      .where('code', '=', options.currencyCode)
114→      .where('network', '=', options.currencyNetwork)
115→      .executeTakeFirst();
116→
117→    if (!currency) {
118→      throw new BadRequestException(
119→        `Currency ${options.currencyCode} on ${options.currencyNetwork} not found`,
120→      );
121→    }
122→
123→    return { currency };
124→  }
125→
126→  /**
127→   * Creates the deposit record in the database
128→   */
129→  private async createDepositRecord(
130→    options: IInitiateDeposit,
131→    poolAccountId: UUID | null,
132→    trx: ControlledTransaction<Database, []>,
133→  ): Promise<Selectable<DepositEntity>> {
134→    const linkExpirationTimeMinutes = options.linkExpirationTimeMinutes ?? 20;
135→    const paymentLinkExpiresAt = new Date();
136→    paymentLinkExpiresAt.setMinutes(
137→      paymentLinkExpiresAt.getMinutes() + linkExpirationTimeMinutes,
138→    );
139→
140→    return await trx
141→      .insertInto('deposit')
142→      .values({
143→        tenantAccountId: options.tenantAccountId,
144→        currencyCode: options.currencyCode,
145→        currencyNetwork: options.currencyNetwork,
146→        amountExpected: options.amount,
147→        commissionAmount: 0,
148→        description: `Deposit ${options.currencyCode} to ${options.currencyNetwork}`,
149→        status: DepositStatus.PENDING,
150→        paymentLink: '', // Temporary, will be updated with URL
151→        paymentLinkExpiresAt,
152→        paymentLinkUsedAt: null,
153→        paymentLinkUsedIp: null,
154→        paymentLinkUsedUserAgent: null,
155→        paymentLinkUsedDevice: null,
156→        paymentLinkUsedDeviceType: null,
157→        depositPoolAccountId: poolAccountId,
158→      })
159→      .returningAll()
160→      .executeTakeFirstOrThrow();
161→  }
162→
163→  /**
164→   * Generates payment link URL and updates the deposit record
165→   */
166→  private async generateAndUpdatePaymentLink(
167→    depositId: UUID,
168→    trx: ControlledTransaction<Database, []>,
169→  ): Promise<string> {
170→    const paymentLinkUrl = `https://deposit.cryptonly.io/${depositId}`;
171→    await trx
172→      .updateTable('deposit')
173→      .set({ paymentLink: paymentLinkUrl })
174→      .where('id', '=', depositId)
175→      .execute();
176→    return paymentLinkUrl;
177→  }
178→
179→  /**
180→   * Schedules the monitoring job for the deposit
181→   */
182→  private async scheduleMonitoringJob(
183→    depositId: UUID,
184→    options: IInitiateDeposit,
185→    currencyId: UUID,
186→  ): Promise<void> {
187→    await this.depositQueue.upsertJobScheduler(
188→      DepositJobsEnum.MONITOR_DEPOSIT,
189→      {
190→        every: 30_000, // every 30 seconds
191→        startDate: new Date(Date.now() + 1_000 * 60 * 1), // 1 minutes from now
192→        endDate: new Date(Date.now() + 50 * 60 * 1000), // 50 minutes from now
193→      },
194→      {
195→        name: DepositJobsEnum.MONITOR_DEPOSIT,
196→        data: {
197→          depositId,
198→          network: options.currencyNetwork,
199→          currencyCode: options.currencyCode,
200→          expectedAmount: options.amount,
201→          currencyId,
202→        },
203→        opts: {
204→          repeatJobKey: `${DepositJobsEnum.MONITOR_DEPOSIT}-${depositId}`,
205→          attempts: 3,
206→          removeOnComplete: false,
207→          removeOnFail: false,
208→        },
209→      },
210→    );
211→  }
212→
213→  /**
214→   * Gets deposit by ID with optional transaction
215→   * @param depositId The deposit ID
216→   * @param trx Optional transaction context (if provided, will use forUpdate lock)
217→   * @returns Deposit entity or undefined if not found
218→   */
219→  async getDepositById(
220→    depositId: UUID,
221→    _trx?: ControlledTransaction<Database, []>,
222→    trxOptions?: {
223→      forUpdate?: boolean;
224→    },
225→  ): Promise<Selectable<DepositEntity> | undefined> {
226→    const trx = _trx ?? (await this.db.startTransaction().execute());
227→    const query = trx
228→      .selectFrom('deposit')
229→      .selectAll()
230→      .where('id', '=', depositId);
231→    if (trxOptions?.forUpdate) {
232→      query.forUpdate();
233→    }
234→
235→    return await query.executeTakeFirst();
236→  }
237→
238→  /**
239→   * Promotes/updates deposit status and related fields
240→   * @param depositId The deposit ID
241→   * @param updates Partial update object with status and optional fields (sweptAt, sweepTransactionHash, etc.)
242→   * @param trx Required transaction context
243→   * @returns Updated deposit entity
244→   */
245→  async promoteDeposit(
246→    depositId: UUID,
247→    updates: {
248→      status?: DepositStatus;
249→      sweptAt?: Date | null;
250→      sweepTransactionHash?: string | null;
251→      amountSweeped?: number | null;
252→      depositTransactionHash?: string | null;
253→      actuallyReceivedAmount?: number | null;
254→      actuallyReceivedAmountUSD?: number | null;
255→      commissionAmount?: number;
256→    },
257→    trx: ControlledTransaction<Database, []>,
258→  ): Promise<Selectable<DepositEntity>> {
259→    return await trx
260→      .updateTable('deposit')
261→      .set(updates)
262→      .where('id', '=', depositId)
263→      .returningAll()
264→      .executeTakeFirstOrThrow();
265→  }
266→}
