  1→import { InjectQueue, Processor, WorkerHost } from '@nestjs/bullmq';
  2→import { DEPOSIT_QUEUE_NAME } from '../constant';
  3→import { Job, Queue } from 'bullmq';
  4→import { Logger, Inject } from '@nestjs/common';
  5→import { DepositJobsEnum } from '../jobs';
  6→import { IMonitorDepositJobPayload } from '../types/initiate-deposit';
  7→import { ICompleteDepositParams } from '../types/complete-deposit';
  8→import { DepositService } from '../services/deposit.service';
  9→import { DATABASE_CONNECTION_TOKEN } from '@shared/database/constant';
 10→import { Db } from '@shared/database/types';
 11→import { DepositStatus } from '@entities/deposit.entity';
 12→import { NetworksService } from '@modules/networks/services/networks.service';
 13→import { CurrencyService } from '@modules/currency/services/currency.service';
 14→import { SupportedNetworks } from '@modules/networks/types/network.type';
 15→import { DepositPoolService } from '../services/deposit-pool.service';
 16→import { BalanceService } from '@modules/balance/services/balance.service';
 17→import { Database } from 'src/db/database.type';
 18→import { ControlledTransaction, Selectable } from 'kysely';
 19→import { DepositEntity } from '@entities/deposit.entity';
 20→import { Commission } from '@shared/utils/commision';
 21→import { OutboxEventsService } from '@modules/events/outbox/outbox-events.service';
 22→import {
 23→  DEPOSIT_COMPITED_OUTBOX_EVENT_NAME,
 24→  IDepositCompitedOutboxEventPayload,
 25→} from '../events/deposit.outbox-event';
 26→import { INetworkTransaction } from '@modules/networks/types/network.type';
