 28→
 29→interface ICheckIncomingTransactionsParams {
 30→  address: string;
 31→  network: string;
 32→  contractAddress: string | null;
 33→  sinceTimestamp: number;
 34→  decimalPlaces: number;
 35→}
 36→
 37→@Processor(DEPOSIT_QUEUE_NAME)
 38→export class DepositProcessor extends WorkerHost {
 39→  private readonly logger = new Logger(DepositProcessor.name);
 40→
 41→  constructor(
 42→    @InjectQueue(DEPOSIT_QUEUE_NAME) private readonly depositQueue: Queue,
 43→    private readonly depositService: DepositService,
 44→    @Inject(DATABASE_CONNECTION_TOKEN) private readonly db: Db,
 45→    private readonly networksService: NetworksService,
 46→    private readonly currencyService: CurrencyService,
 47→    private readonly depositPoolService: DepositPoolService,
 48→    private readonly balanceService: BalanceService,
 49→    private readonly tenantAccountService: TenantAccountService,
 50→    private readonly outboxEventsService: OutboxEventsService,
 51→  ) {
 52→    super();
 53→  }
 54→
 55→  async process(job: Job<IMonitorDepositJobPayload>): Promise<void> {
 56→    if (job.name === DepositJobsEnum.MONITOR_DEPOSIT) {
 57→      await this.monitorDeposit(job as Job<IMonitorDepositJobPayload>);
 58→      return;
 59→    }
 60→  }
 61→
 62→  /**
 63→   * Monitors a deposit address for incoming transactions
 64→   * Checks the blockchain for transactions matching the deposit criteria
 65→   */
 66→  private async monitorDeposit(
 67→    job: Job<IMonitorDepositJobPayload>,
 68→  ): Promise<void> {
 69→    const { depositId } = job.data;
 70→    const trx = await this.db.startTransaction().execute();
 71→    this.logger.log({ message: 'Monitoring deposit', depositId });
 72→    try {
 73→      const deposit = await this.depositService.getDepositById(depositId, trx, {
 74→        forUpdate: true,
 75→      });
 76→      const currency = await this.currencyService.getCurrencyByCodeAndNetwork(
 77→        job.data.currencyCode,
 78→        job.data.network as SupportedNetworks,
 79→      );
 80→
 81→      // Early returns for invalid/processed deposits
 82→      if (await this.shouldStopMonitoring(deposit, trx)) {
 83→        await this.depositPoolService.unlockPoolAccount(
 84→          deposit.depositPoolAccountId,
 85→          currency.id,
 86→          trx,
 87→        );
 88→        await trx.commit().execute();
 89→        await this.removeRepeatableMonitorJob(job.repeatJobKey);
 90→        return;
 91→      }
 92→
 93→      const poolAccount = await this.depositPoolService.getAccountById(
 94→        deposit.depositPoolAccountId,
 95→      );
 96→
 97→      // Get currency to determine contract address
 98→
 99→      if (!currency) {
100→        this.logger.warn({
101→          message: 'Currency not found',
102→          currencyCode: job.data.currencyCode,
103→          network: job.data.network,
104→        });
105→        await trx.rollback().execute();
106→        return;
107→      }
108→
109→      // Check for incoming transactions after deposit creation time
110→      const depositCreatedAt = deposit.createdAt.getTime();
111→      const incomingTransactions = await this.checkIncomingTransactions({
112→        address: poolAccount.address,
113→        network: job.data.network,
114→        contractAddress: currency.contractAddress,
115→        sinceTimestamp: depositCreatedAt,
116→        decimalPlaces: currency.decimalPlaces,
117→      });
118→
119→      // Find matching transaction for this deposit
120→      const matchingTransaction = await this.findMatchingTransaction(
121→        incomingTransactions,
122→        deposit.amountExpected,
123→        currency.decimalPlaces,
124→        currency.minDepositAmount, // minAmount: use expected amount as minimum when not strict
125→        deposit.createdAt, // dateFrom: use the deposit creation time as the date from
126→        deposit.strictAmountExpected, // amountStrict: use the deposit's strict flag
127→      );
128→
129→      if (matchingTransaction) {
130→        // Complete the deposit
131→        await this.completeDeposit(
132→          {
133→            depositId: deposit.id,
134→            network: job.data.network,
135→            currencyCode: job.data.currencyCode,
136→            currencyId: job.data.currencyId,
137→            expectedAmount: job.data.expectedAmount,
138→            poolAccountId: poolAccount.id,
139→            tenantAccountId: deposit.tenantAccountId,
140→            failed: false,
141→            transaction: matchingTransaction.transaction,
142→            monitorJobKey: job.repeatJobKey,
143→          },
144→          trx,
145→        );
146→
147→        await this.depositPoolService.unlockPoolAccount(
148→          poolAccount.id,
149→          currency.id,
150→          trx,
151→        );
152→      }
153→      await trx.commit().execute();
154→    } catch (error) {
155→      await trx.rollback().execute();
156→      this.logger.error({
157→        error,
158→        message: 'Failed to monitor deposit',
159→        depositId,
160→      });
161→      // Don't throw - let the job retry
162→    }
163→  }
164→
165→  /**
166→   * Checks if monitoring should stop (deposit not found, already processed, expired, etc.)
167→   */
168→  private async shouldStopMonitoring(
169→    deposit: Selectable<DepositEntity> | undefined,
170→    trx: ControlledTransaction<Database, []>,
171→  ): Promise<boolean> {
172→    if (!deposit) {
173→      this.logger.warn({
174→        message: 'Deposit not found',
175→        depositId: deposit?.id,
176→      });
177→      return true;
178→    }
179→
180→    if (deposit.status !== DepositStatus.PENDING) {
181→      this.logger.log({
182→        message: 'Deposit already processed',
183→        depositId: deposit.id,
184→        status: deposit.status,
185→      });
186→      return true;
187→    }
188→
189→    if (new Date(deposit.paymentLinkExpiresAt) < new Date()) {
190→      this.logger.warn({
191→        message: 'Deposit link expired',
192→        depositId: deposit.id,
193→      });
194→      await this.depositService.promoteDeposit(
195→        deposit.id,
196→        { status: DepositStatus.EXPIRED },
197→        trx,
198→      );
199→      return true;
200→    }
201→
202→    return false;
203→  }
204→
205→  /**
206→   * Removes the repeatable MONITOR_DEPOSIT job once we no longer need to monitor.
207→   */
208→  async removeRepeatableMonitorJob(repeatJobKey: string): Promise<void> {
209→    try {
210→      await this.depositQueue.removeJobScheduler(repeatJobKey);
211→      this.logger.debug({
212→        message: 'Removed repeatable monitor job',
213→        repeatJobKey,
214→      });
215→    } catch (error) {
216→      this.logger.error({
217→        error,
218→        message: 'Failed to remove repeatable monitor job',
219→        repeatJobKey,
220→      });
221→    }
222→  }
223→
224→  /**
225→   * Checks for incoming transactions to the deposit address after the deposit creation time
226→   * @param params Parameters object containing address, network, contractAddress, sinceTimestamp, decimalPlaces, minAmount, and optional amountStrict
227→   * @returns Array of incoming transactions with amounts in human-readable format
228→   */
229→  private async checkIncomingTransactions(
230→    params: ICheckIncomingTransactionsParams,
231→  ): Promise<Array<INetworkTransaction>> {
232→    const { address, network, contractAddress, sinceTimestamp, decimalPlaces } =
233→      params;
234→    try {
235→      const transactions = await this.networksService.getTransactionHistory({
236→        network: network as SupportedNetworks,
237→        address,
238→        contractAddress: contractAddress ? contractAddress : null,
239→        sinceTimestamp,
240→        onlyTo: true,
241→        limit: 10,
242→        onlyConfirmed: true,
243→        decimalPlaces,
244→      });
245→
246→      // Convert amounts from smallest unit to human-readable format
247→      // TronGrid returns amounts in smallest units (SUN for TRX, smallest unit for TRC20)
248→      // Network services return raw amounts, we need to convert them here
249→      return transactions;
250→    } catch (error) {
251→      this.logger.error({
252→        error,
253→        message: 'Failed to check incoming transactions',
254→        address,
255→        network,
256→        contractAddress,
257→      });
258→      return [];
259→    }
260→  }
261→
262→  /**
263→   * Finds a transaction matching the deposit amount (within tolerance)
264→   * @param transactions Array of incoming transactions
265→   * @param expectedAmount Expected deposit amount
266→   * @param decimalPlaces Decimal places for amount comparison
267→   * @returns Matching transaction or null
268→   */
269→  private async findMatchingTransaction(
270→    transactions: Array<INetworkTransaction>,
271→    expectedAmount: number,
272→    _decimalPlaces: number,
273→    minAmount: number,
274→    dateFrom: Date,
275→    amountStrict?: boolean,
276→  ): Promise<{
277→    transaction: INetworkTransaction;
278→  } | null> {
279→    if (transactions.length === 0) {
280→      return null;
281→    }
282→    const sweepRecords = await this.networksService.getSweepRecord(
283→      dateFrom,
284→      new Date(),
285→    );
286→    const sweepRecordsMap = new Map<string, 1>();
287→    for (const sweepRecord of sweepRecords) {
288→      sweepRecordsMap.set(sweepRecord.transactionHash, 1);
289→    }
290→    for (const tx of transactions) {
291→      if (sweepRecordsMap.has(tx.transactionHash)) {
292→        continue;
293→      }
294→      if (amountStrict) {
295→        const txAmount = parseFloat(tx.amount);
296→        const tolerance = expectedAmount * 0.001;
297→        const amountFrom = txAmount - tolerance;
298→        const amountTo = txAmount + tolerance;
299→        if (txAmount >= amountFrom && txAmount <= amountTo) {
300→          return { transaction: tx };
301→        }
302→        continue;
303→      } else {
304→        const txAmount = parseFloat(tx.amount);
305→        if (txAmount >= minAmount) {
306→          return { transaction: tx };
307→        }
308→        continue;
309→      }
310→    }
311→
312→    return null;
313→  }
314→
315→  /**
316→   * Completes deposit: marks deposit as completed, updates balance, unlocks pool account
317→   * Main job in flow - runs after sweep funds child job completes
318→   */
319→  private async completeDeposit(
320→    payload: ICompleteDepositParams & { failed: boolean },
321→    trx: ControlledTransaction<Database, []>,
322→  ): Promise<void> {
323→    const {
324→      depositId,
325→      tenantAccountId,
326→      currencyId,
327→      poolAccountId,
328→      network,
329→      transaction,
330→      monitorJobKey,
331→    } = payload;
332→
333→    try {
334→      // Get deposit information
335→      const deposit = await this.depositService.getDepositById(depositId, trx, {
336→        forUpdate: true,
337→      });
338→
339→      if (!deposit) {
340→        this.logger.error({ message: 'Deposit not found', depositId });
341→        return;
342→      }
343→
344→      const tenantAccount =
345→        await this.tenantAccountService.getById(tenantAccountId);
346→
347→      // Get currency to check if it's base currency
348→      const currency = await this.currencyService.getCurrencyById(currencyId);
349→
350→      // Get balance record for tenant account
351→      const existingBalance = await trx
352→        .selectFrom('balance')
353→        .selectAll()
354→        .where('tenantAccountId', '=', tenantAccountId)
355→        .where('currencyId', '=', currencyId)
356→        .executeTakeFirst();
357→
358→      if (!existingBalance) {
359→        this.logger.error({
360→          message: 'Balance not found',
361→          depositId,
362→          tenantAccountId,
363→          currencyId,
364→        });
365→        throw new Error('Balance not found');
366→      }
367→
368→      const commissionInstance = new Commission(
369→        transaction.amount,
370→        currency.depositCommission,
371→      );
372→      const commissionAmount = commissionInstance.only();
373→      const balanceToIncrease = commissionInstance.with();
374→
375→      // Increase balance by expected amount
376→      await this.balanceService.increaseBalance(
377→        existingBalance.id,
378→        balanceToIncrease,
379→        currency.decimalPlaces,
380→        trx,
381→      );
382→
383→      // Update deposit status to completed (sweep transaction hash should already be set by sweep job)
384→      const actuallyReceivedAmountUSD = await this.currencyService.amountToUSD(
385→        transaction.amount,
386→        currency.code,
387→      );
388→      await this.depositService.promoteDeposit(
389→        depositId,
390→        {
391→          status: DepositStatus.COMPLETED,
392→          commissionAmount: parseFloat(commissionAmount),
393→          depositTransactionHash: transaction.transactionHash,
394→          actuallyReceivedAmount: parseFloat(transaction.amount),
395→          actuallyReceivedAmountUSD: parseFloat(actuallyReceivedAmountUSD),
396→        },
397→        trx,
398→      );
399→
400→      this.logger.log({
401→        message: 'Deposit completed',
402→        depositId,
403→        amount: transaction.amount,
404→      });
405→
406→      this.outboxEventsService.publish<IDepositCompitedOutboxEventPayload>(
407→        DEPOSIT_COMPITED_OUTBOX_EVENT_NAME,
408→        {
409→          tenantId: tenantAccount.tenantId,
410→          depositId,
411→          network: network as SupportedNetworks,
412→          currencyCode: currency.code,
413→          amount: transaction.amount,
414→          commissionAmount: parseFloat(commissionAmount),
415→          poolAccountId,
416→          depositTransactionHash: transaction.transactionHash,
417→          status: deposit.status,
418→          monitorJobKey,
419→        },
420→        3,
421→        trx,
422→      );
423→    } catch (error) {
424→      this.logger.error({
425→        error,
426→        message: 'Failed to complete deposit',
427→        depositId,
428→      });
429→      throw error;
430→    }
431→  }
432→}
