 9→@Injectable()
10→export class OutstandingTronAccountService {
11→  constructor(
12→    @Inject(networksConfigs.KEY)
13→    private readonly networksConfig: ConfigType<typeof networksConfigs>,
14→    private readonly tronNetworkService: TronNetworkService,
15→    private readonly notificationsService: NotificationsService,
16→  ) {
17→    this.tronWeb = new TronWeb({
18→      fullHost: this.networksConfig.tron.url,
19→    });
20→    this.tronWeb.setAddress(
21→      this.networksConfig.tron.outstandingAccount.address,
22→    );
