24→      this.networksConfig.tron.outstandingAccount.privateKey,
25→    );
26→  }
27→
28→  private readonly tronWeb: TronWeb;
29→
30→  private readonly activationCost = new Decimal(0.1); // 0.1 TRX
31→
32→  async activateAccounts(addresses: string[]): Promise<void> {
33→    if (addresses.length === 0) {
34→      return;
35→    }
36→    const balance = await this.tronNetworkService.getTrxBalance(
37→      this.networksConfig.tron.outstandingAccount.address,
38→    );
39→    console.log({ outstandingAccountBalance: balance });
40→    if (
41→      new Decimal(balance).lessThan(this.activationCost.mul(addresses.length))
42→    ) {
43→      await this.notificationsService.sendNotification(
44→        `Insufficient balance to activate tron accounts`,
45→      );
46→      throw new Error('Insufficient balance');
47→    }
48→
49→    for (const address of addresses) {
50→      await this.tronWeb.trx.sendTrx(address, 100000);
51→    }
52→  }
