  id: Generated<UUID>;
  address: string;  // Pool account's address
  privateKey: string;  // For sweeping
  network: SupportedNetworks;  // Which network this pool belongs to
  lastMonitorAt: ColumnType<Date, Date, Date> | null;
  lastDepositAt: ColumnType<Date, Date, Date> | null;
  createdAt: ColumnType<Date, undefined, never>;
  updatedAt: ColumnType<Date, undefined, never>;
