```

Prevents concurrent deposits from using the same pool account for the same currency.

### 3.4 Deposit Entity
```typescript
export interface DepositEntity {
  id: Generated<UUID>;
  tenantAccountId: UUID;
  currencyCode: string;
  currencyNetwork: SupportedNetworks;  // Network reference
  amountExpected: number;
  strictAmountExpected: boolean;
  actuallyReceivedAmount: number | null;
  actuallyReceivedAmountUSD: number | null;
  commissionAmount: number;
  description: string;
  status: DepositStatus;  // PENDING, COMPLETED, FAILED, EXPIRED
  paymentLink: string;
  paymentLinkExpiresAt: ColumnType<Date, Date, never>;
  paymentLinkUsedAt: Date | null;
  depositPoolAccountId: UUID | null;  // Which pool account received this deposit
  depositTransactionHash: string | null;  // Hash of user's deposit TX
